import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const AdminDashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    Promise.all([
      api.get('/bookings'),
      api.get('/packages'),
      api.get('/destinations'),
      api.get('/dashboard')  // 🔥 IMPORTANT: dashboard aggregation API
    ])
      .then(([bkgs, pkgs, dests, dashboard]) => {
        console.log("Dashboard response:", dashboard.data); // 🔥 debug

        setStats({
          // Existing stats
          bookings: bkgs.data?.data?.length ?? 0,
          packages: pkgs.data?.data?.length ?? 0,
          destinations: dests.data?.data?.length ?? 0,

          // 🔥 New aggregation stats
          totalUsers: dashboard.data?.totalUsers ?? 0,
          totalBookings: dashboard.data?.totalBookings ?? 0,
          totalRevenue: dashboard.data?.totalRevenue ?? 0,
          mostBookedPackage:
            dashboard.data?.mostBookedPackage ?? 'N/A',
        });
      })
      .catch((err) => {
        console.error("Dashboard error:", err);
      });
  }, []);

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>👑 Admin Dashboard</h1>
        <p className={styles.sub}>System overview</p>

        {stats && (
          <div className={styles.grid}>
            {/* Existing cards */}
            <StatCard
              icon="📅"
              label="Total Bookings"
              value={stats.bookings}
              to="/admin/bookings"
            />

            <StatCard
              icon="✈️"
              label="Total Packages"
              value={stats.packages}
              to="/admin/packages"
            />

            <StatCard
              icon="📍"
              label="Destinations"
              value={stats.destinations}
              to="/admin/destinations"
            />

            {/* 🔥 New analytics cards */}
            <StatCard
              icon="👥"
              label="Total Users"
              value={stats.totalUsers}
              to="/admin/users"
            />

            <StatCard
              icon="💰"
              label="Total Revenue"
              value={`₹ ${stats.totalRevenue}`}
              to="/admin"
            />

            <StatCard
              icon="🔥"
              label="Most Booked Package"
              value={stats.mostBookedPackage}
              to="/admin/packages"
            />
          </div>
        )}
      </div>
    </>
  );
};

const StatCard = ({ icon, label, value, to }) => (
  <Link to={to} className={styles.statCard}>
    <span className={styles.statIcon}>{icon}</span>
    <span className={styles.statValue}>{value}</span>
    <span className={styles.statLabel}>{label}</span>
  </Link>
);

export default AdminDashboard;
